def deterministic_scenarios() -> List[Dict[str, Any]]:
    return [dict(s) for s in SCENARIOS]


def write_scenarios(out_dir: str | Path = "app/eval/scenarios") -> List[Path]:
    out_dir = Path(out_dir)
    written: List[Path] = []
    for scenario in deterministic_scenarios():
        path = out_dir / f"{scenario['scenario_id']}.json"
        written.append(write_scenario(scenario, path))
    return written


if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description="Write deterministic CP4 scenario JSON files.")
    parser.add_argument("--out-dir", default="app/eval/scenarios")
    args = parser.parse_args()
    for path in write_scenarios(args.out_dir):
        print(path)
